import 'city_models.dart';

List<ProvinceEntry> get provinces => _provinces;
final List<ProvinceEntry> _provinces = _decodeCityRows(_cityRows);
List<ProvinceEntry> _decodeCityRows(List<String> rows) {
  final provinceMap = <String, List<CityEntry>>{};
  for (final row in rows) {
    final parts = row.split('|');
    final areaParts = parts.length > 5 && parts[5].isNotEmpty
        ? parts[5].split(';')
        : const <String>[];
    final areas = areaParts.map((part) {
      final fields = part.split(',');
      return CityArea(
          name: fields[0],
          latitude: double.parse(fields[1]),
          longitude: double.parse(fields[2]));
    }).toList(growable: false);
    provinceMap.putIfAbsent(parts[0], () => <CityEntry>[]).add(CityEntry(
        name: parts[1],
        latitude: double.parse(parts[2]),
        longitude: double.parse(parts[3]),
        areas: areas));
  }
  return provinceMap.entries
      .map((entry) => ProvinceEntry(
          name: entry.key, cities: List<CityEntry>.unmodifiable(entry.value)))
      .toList(growable: false);
}

